cedar_text:
@id("permit-all")
@severity("info")
@reason("baseline: allow everything")
permit(
  principal,
  action,
  resource
);

@id("slippage-50bp")
@severity("deny")
@reason("slippage exceeds 50bp")
forbid(
  principal is Wallet,
  action == Amm::Action::"Swap",
  resource is Protocol
)
when {
  context.slippageBp > 50
};

@id("price-impact-100bp-warn")
@severity("warn")
@reason("price impact exceeds 100bp")
permit(
  principal is Wallet,
  action == Amm::Action::"Swap",
  resource is Protocol
)
when {
  context.priceImpactBp > 100
};

@id("block-erc20-approve")
@severity("deny")
@reason("all ERC-20 approvals blocked")
forbid(
  principal is Wallet,
  action == Token::Action::"Erc20Approve",
  resource is Protocol
);

@id("monitor-transfer")
@severity("info")
@reason("transfer logged for monitoring")
permit(
  principal is Wallet,
  action == Token::Action::"Erc20Transfer",
  resource is Protocol
);

@id("block-specific-token")
@severity("deny")
@reason("swap touches blocked token")
forbid(
  principal is Wallet,
  action == Amm::Action::"Swap",
  resource is Protocol
)
when {
  context.tokenIn.key has address && context.tokenIn.key.address == "0xdac17f958d2ee523a2206206994597c13d831ec7"
  || context.tokenOut.key has address && context.tokenOut.key.address == "0xdac17f958d2ee523a2206206994597c13d831ec7"
};

@id("block-large-transfer-usd")
@severity("deny")
@reason("transfer value exceeds threshold")
forbid(
  principal is Wallet,
  action == Token::Action::"Erc20Transfer",
  resource is Protocol
)
when {
  context has amountUsd && context.amountUsd > decimal("10000.0")
};
